INSERT INTO dbo.Artists (Id, Name, NormalizedName)
SELECT a.Id, a.Name, a.NormalizedName
FROM @Artists a
WHERE NOT EXISTS (
    SELECT 1
    FROM dbo.Artists existing
    WHERE existing.Id = a.Id OR existing.NormalizedName = a.NormalizedName
);

DECLARE @Albums TABLE
