INSERT INTO dbo.MusicTracks (Id, ArtistId, AlbumId, Title, NormalizedTitle, DurationSeconds)
SELECT
    t.Id,
    t.ArtistId,
    t.AlbumId,
    t.Title,
    UPPER(LTRIM(RTRIM(t.Title))) AS NormalizedTitle,
    t.DurationSeconds
FROM @Tracks t
WHERE NOT EXISTS (
    SELECT 1
    FROM dbo.MusicTracks existing
    WHERE existing.Title = t.Title
      AND existing.AlbumId = t.AlbumId
);

